example.code:
// See templates/entity-builder.ts for full implementation
const activeAdmin = new UserBuilder()
  .withEmail('admin@example.com')
  .withRole('admin')
  .asActive()
  .build();

// Test only specifies what matters
const inactiveUser = new UserBuilder().asInactive().build();

// Object Mother returns Builder — caller can override
const admin = UserMother.admin().withEmail('custom@example.com').build();

// Or use the preset as-is
const guest = UserMother.guest().build();

// Compose scenarios
const shippedOrder = OrderMother.paid().asShipped().build();
